{
  "name": "Chronos War Room",
  "description": "An alternate history and war scenario generator that simulates complex global events based on user input, visualized through a tactical timeline interface."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface ScenarioInput {
  name: string;
  description: string;
  continent: string;
  additionalContext: string;
  eventCount: number;
}

export interface WarEvent {
  id: string;
  date: string;
  title: string;
  description: string;
  strategicImpact: number; // 1-10
  factionsInvolved: string[];
  location: string;
}

export interface GenerationResult {
  scenarioName: string;
  overview: string;
  events: WarEvent[];
}

export type AppState = 'IDLE' | 'GENERATING' | 'RESULT';

import { GoogleGenAI, Type } from "@google/genai";
import { ScenarioInput, GenerationResult } from "../types";

export const generateWarScenario = async (input: ScenarioInput): Promise<GenerationResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `Generate an alternate history/war scenario titled "${input.name}".
  Continent: ${input.continent}
  Premise: ${input.description}
  Additional Context: ${input.additionalContext}
  Required Events: Exactly ${input.eventCount} chronological events.

  For each event, provide:
  1. A specific date (historical format or relative like 'Day 1', 'Year 3').
  2. A title.
  3. A detailed description of the military or geopolitical action.
  4. A strategic impact score from 1 (minor) to 10 (total shift).
  5. Key factions or nations involved.
  6. Specific location within ${input.continent}.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          scenarioName: { type: Type.STRING },
          overview: { type: Type.STRING },
          events: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                date: { type: Type.STRING },
                title: { type: Type.STRING },
                description: { type: Type.STRING },
                strategicImpact: { type: Type.NUMBER },
                factionsInvolved: {
                  type: Type.ARRAY,
                  items: { type: Type.STRING }
                },
                location: { type: Type.STRING }
              },
              required: ['id', 'date', 'title', 'description', 'strategicImpact', 'factionsInvolved', 'location']
            }
          }
        },
        required: ['scenarioName', 'overview', 'events']
      },
      thinkingConfig: { thinkingBudget: 4000 }
    }
  });

  const resultStr = response.text.trim();
  return JSON.parse(resultStr) as GenerationResult;
};

import React, { useState, useCallback } from 'react';
import { ScenarioInput, GenerationResult, AppState } from './types';
import { generateWarScenario } from './services/gemini';
import InputPanel from './components/InputPanel';
import TimelineView from './components/TimelineView';
import Header from './components/Header';
import LoadingScreen from './components/LoadingScreen';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>('IDLE');
  const [result, setResult] = useState<GenerationResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleGenerate = useCallback(async (input: ScenarioInput) => {
    setState('GENERATING');
    setError(null);
    try {
      const data = await generateWarScenario(input);
      setResult(data);
      setState('RESULT');
    } catch (err) {
      console.error(err);
      setError('Failed to generate intelligence. The server might be jammed. Please try again.');
      setState('IDLE');
    }
  }, []);

  const handleReset = useCallback(() => {
    setState('IDLE');
    setResult(null);
    setError(null);
  }, []);

  return (
    <div className="min-h-screen flex flex-col max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 gap-8 relative">
      <Header />

      {state === 'IDLE' && (
        <div className="flex flex-col items-center justify-center flex-1">
          <InputPanel onGenerate={handleGenerate} isSubmitting={false} />
          {error && (
            <div className="mt-6 p-4 bg-red-900/30 border border-red-500 rounded-lg text-red-200 mono text-sm flex items-center gap-3">
              <span className="animate-pulse">⚠️</span>
              {error}
            </div>
          )}
        </div>
      )}

      {state === 'GENERATING' && (
        <LoadingScreen />
      )}

      {state === 'RESULT' && result && (
        <TimelineView 
          result={result} 
          onBack={handleReset} 
        />
      )}

      {/* Footer Branding */}
      <footer className="text-slate-500 mono text-xs text-center py-4 border-t border-slate-800/50 mt-auto">
        &copy; 2024 STRATOS-INTEL // CLASSIFIED // LEVEL 4 CLEARANCE REQUIRED
      </footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { ScenarioInput } from '../types';

interface Props {
  onGenerate: (input: ScenarioInput) => void;
  isSubmitting: boolean;
}

const InputPanel: React.FC<Props> = ({ onGenerate, isSubmitting }) => {
  const [formData, setFormData] = useState<ScenarioInput>({
    name: '',
    description: '',
    continent: 'Europe',
    additionalContext: '',
    eventCount: 15
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.description) return;
    onGenerate(formData);
  };

  const continents = ['North America', 'South America', 'Europe', 'Asia', 'Africa', 'Oceania', 'Antarctica', 'Global'];

  return (
    <div className="w-full max-w-2xl bg-slate-900/40 border border-slate-800 p-6 sm:p-8 rounded-xl backdrop-blur-sm shadow-2xl relative overflow-hidden group">
      {/* Decorative corners */}
      <div className="absolute top-0 left-0 w-4 h-4 border-t-2 border-l-2 border-emerald-500 opacity-50 group-hover:opacity-100 transition-opacity"></div>
      <div className="absolute top-0 right-0 w-4 h-4 border-t-2 border-r-2 border-emerald-500 opacity-50 group-hover:opacity-100 transition-opacity"></div>
      <div className="absolute bottom-0 left-0 w-4 h-4 border-b-2 border-l-2 border-emerald-500 opacity-50 group-hover:opacity-100 transition-opacity"></div>
      <div className="absolute bottom-0 right-0 w-4 h-4 border-b-2 border-r-2 border-emerald-500 opacity-50 group-hover:opacity-100 transition-opacity"></div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="space-y-1">
          <label className="text-slate-400 mono text-xs uppercase tracking-widest font-bold">Operation Name</label>
          <input
            type="text"
            required
            placeholder="e.g., The Crimson Winter, Operation Zephyr..."
            className="w-full bg-slate-950 border border-slate-700 rounded-lg p-3 text-white focus:outline-none focus:border-emerald-500 transition-colors placeholder:text-slate-700"
            value={formData.name}
            onChange={(e) => setFormData({ ...formData, name: e.target.value })}
          />
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
          <div className="space-y-1">
            <label className="text-slate-400 mono text-xs uppercase tracking-widest font-bold">Theater of Operations</label>
            <select
              className="w-full bg-slate-950 border border-slate-700 rounded-lg p-3 text-white focus:outline-none focus:border-emerald-500 transition-colors"
              value={formData.continent}
              onChange={(e) => setFormData({ ...formData, continent: e.target.value })}
            >
              {continents.map(c => <option key={c} value={c}>{c}</option>)}
            </select>
          </div>
          <div className="space-y-1">
            <label className="text-slate-400 mono text-xs uppercase tracking-widest font-bold">Event Count (1-100)</label>
            <input
              type="number"
              min="1"
              max="100"
              required
              className="w-full bg-slate-950 border border-slate-700 rounded-lg p-3 text-white focus:outline-none focus:border-emerald-500 transition-colors"
              value={formData.eventCount}
              onChange={(e) => setFormData({ ...formData, eventCount: Math.min(100, Math.max(1, parseInt(e.target.value) || 1)) })}
            />
          </div>
        </div>

        <div className="space-y-1">
          <label className="text-slate-400 mono text-xs uppercase tracking-widest font-bold">Primary Conflict / Event</label>
          <textarea
            required
            placeholder="Describe the inciting incident or main conflict..."
            rows={3}
            className="w-full bg-slate-950 border border-slate-700 rounded-lg p-3 text-white focus:outline-none focus:border-emerald-500 transition-colors placeholder:text-slate-700 resize-none"
            value={formData.description}
            onChange={(e) => setFormData({ ...formData, description: e.target.value })}
          />
        </div>

        <div className="space-y-1">
          <label className="text-slate-400 mono text-xs uppercase tracking-widest font-bold">Intelligence Context (Optional)</label>
          <textarea
            placeholder="Technology levels, specific political tensions, previous history..."
            rows={3}
            className="w-full bg-slate-950 border border-slate-700 rounded-lg p-3 text-white focus:outline-none focus:border-emerald-500 transition-colors placeholder:text-slate-700 resize-none"
            value={formData.additionalContext}
            onChange={(e) => setFormData({ ...formData, additionalContext: e.target.value })}
          />
        </div>

        <button
          type="submit"
          disabled={isSubmitting}
          className="w-full group relative flex items-center justify-center gap-3 bg-emerald-600 hover:bg-emerald-500 text-white font-bold py-4 rounded-lg transition-all shadow-[0_0_20px_rgba(16,185,129,0.2)] disabled:opacity-50"
        >
          <span className="absolute left-4 opacity-30 group-hover:translate-x-1 transition-transform">>>></span>
          INITIALIZE SIMULATION
          <span className="absolute right-4 opacity-30 group-hover:-translate-x-1 transition-transform">&lt;&lt;&lt;</span>
        </button>
      </form>
    </div>
  );
};

export default InputPanel;

