    name: e.date,
    impact: e.strategicImpact,
    index: i + 1
  }));

  return (
    <div className="flex flex-col gap-8 animate-in fade-in duration-1000">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6 border-l-4 border-emerald-500 pl-6 py-2">
