import { GoogleGenAI, Type } from "@google/genai";
import { ScenarioInput, GenerationResult } from "../types";

export const generateWarScenario = async (input: ScenarioInput): Promise<GenerationResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `Generate an alternate history/war scenario titled "${input.name}".
  Continent: ${input.continent}
  Historical Timeframe: From ${input.startYear} to ${input.endYear}.
  Premise: ${input.description}
  Additional Context: ${input.additionalContext}
  Required Events: Exactly ${input.eventCount} chronological events spanning the requested timeframe.

  For each event, provide:
  1. A specific date (using the requested ${input.startYear}/${input.endYear} format, e.g., 'August 12, 1200 BC' or 'Day 45 of 2024 AD').
  2. A title.
  3. A detailed description of the military or geopolitical action.
  4. A strategic impact score from 1 (minor) to 10 (total shift).
  5. Key factions or nations involved.
  6. Specific location within ${input.continent}.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          scenarioName: { type: Type.STRING },
          overview: { type: Type.STRING },
          events: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                date: { type: Type.STRING },
                title: { type: Type.STRING },
                description: { type: Type.STRING },
                strategicImpact: { type: Type.NUMBER },
                factionsInvolved: {
                  type: Type.ARRAY,
                  items: { type: Type.STRING }
                },
                location: { type: Type.STRING }
              },
              required: ['id', 'date', 'title', 'description', 'strategicImpact', 'factionsInvolved', 'location']
            }
          }
        },
        required: ['scenarioName', 'overview', 'events']
      },
      thinkingConfig: { thinkingBudget: 4000 }
    }
  });

  const resultStr = response.text.trim();
  return JSON.parse(resultStr) as GenerationResult;
};

import React, { useState } from 'react';
