import { GoogleGenAI, Type } from "@google/genai";
import { ScenarioInput, GenerationResult } from "../types";

export const generateWarScenario = async (input: ScenarioInput): Promise<GenerationResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Generate an alternate history/war scenario titled "${input.name}".
  Continent: ${input.continent}
  Historical Timeframe: From ${input.startYear} to ${input.endYear}.
  Premise: ${input.description}
  Additional Context: ${input.additionalContext}
  Required Events: Exactly ${input.eventCount} chronological events spanning the requested timeframe.

  For each event, provide:
  1. A specific date (using the requested ${input.startYear}/${input.endYear} format).
  2. A title.
  3. A detailed description of the military or geopolitical action.
  4. A strategic impact score from 1 (minor) to 10 (total shift).
  5. Key factions or nations involved.
  6. Specific location within ${input.continent}.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          scenarioName: { type: Type.STRING },
          overview: { type: Type.STRING },
          events: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                date: { type: Type.STRING },
                title: { type: Type.STRING },
                description: { type: Type.STRING },
                strategicImpact: { type: Type.NUMBER },
                factionsInvolved: {
                  type: Type.ARRAY,
                  items: { type: Type.STRING }
                },
                location: { type: Type.STRING }
              },
              required: ['id', 'date', 'title', 'description', 'strategicImpact', 'factionsInvolved', 'location']
            }
          }
        },
        required: ['scenarioName', 'overview', 'events']
      },
      thinkingConfig: { thinkingBudget: 2000 }
    }
  });

  const resultStr = response.text.trim();
  try {
    return JSON.parse(resultStr) as GenerationResult;
  } catch (e) {
    console.error("Failed to parse AI response", resultStr);
    throw new Error("Intelligence report corrupted. Try a shorter timeframe or fewer events.");
  }
};

import React, { useState, useCallback } from 'react';
import { ScenarioInput, GenerationResult, AppState } from './types';
import { generateWarScenario } from './services/gemini';
import InputPanel from './components/InputPanel';
import TimelineView from './components/TimelineView';
import Header from './components/Header';
import LoadingScreen from './components/LoadingScreen';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>('IDLE');
  const [result, setResult] = useState<GenerationResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleGenerate = useCallback(async (input: ScenarioInput) => {
    setState('GENERATING');
    setError(null);
    try {
      const data = await generateWarScenario(input);
      setResult(data);
      setState('RESULT');
    } catch (err: any) {
      console.error(err);
      setError(err.message || 'Failed to generate intelligence. The server might be jammed. Please try again.');
      setState('IDLE');
    }
  }, []);

  const handleReset = useCallback(() => {
    setState('IDLE');
    setResult(null);
    setError(null);
  }, []);

  return (
    <div className="min-h-screen flex flex-col max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 gap-8 relative">
      <Header />

      {state === 'IDLE' && (
        <div className="flex flex-col items-center justify-center flex-1">
          <InputPanel onGenerate={handleGenerate} isSubmitting={state === 'GENERATING'} />
          {error && (
            <div className="mt-6 p-4 bg-red-900/30 border border-red-500 rounded-lg text-red-200 mono text-sm flex items-center gap-3">
              <span className="animate-pulse">⚠️</span>
              {error}
            </div>
          )}
        </div>
      )}

      {state === 'GENERATING' && (
        <LoadingScreen />
      )}

      {state === 'RESULT' && result && (
        <TimelineView 
          result={result} 
          onBack={handleReset} 
        />
      )}

      {/* Footer Branding */}
      <footer className="text-slate-500 mono text-xs text-center py-4 border-t border-slate-800/50 mt-auto">
        &copy; 2024 STRATOS-INTEL // CLASSIFIED // LEVEL 4 CLEARANCE REQUIRED
      </footer>
    </div>
  );
};

export default App;

