export type AppState = 'IDLE' | 'GENERATING' | 'RESULT';

import { GoogleGenAI, Type } from "@google/genai";
import { ScenarioInput, GenerationResult } from "../types";

export const generateWarScenario = async (input: ScenarioInput): Promise<GenerationResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Generate a detailed alternate history/war scenario titled "${input.name}".
  Continent: ${input.continent}
  Historical Timeframe: From ${input.startYear} to ${input.endYear}.
  Premise: ${input.description}
  Additional Context: ${input.additionalContext}
  Required Events: Exactly ${input.eventCount} chronological events.

  For each event, provide:
  1. A specific date.
  2. A title.
  3. A detailed military/geopolitical description.
  4. A strategic impact score (1-10).
  5. Key factions.
  6. Specific location name.
  7. Approximate geographic coordinates (latitude and longitude) for the location.

  IMPORTANT: Return the response strictly as JSON.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          scenarioName: { type: Type.STRING },
          overview: { type: Type.STRING },
          events: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                date: { type: Type.STRING },
                title: { type: Type.STRING },
                description: { type: Type.STRING },
                strategicImpact: { type: Type.NUMBER },
                factionsInvolved: {
                  type: Type.ARRAY,
                  items: { type: Type.STRING }
                },
                location: { type: Type.STRING },
                latitude: { type: Type.NUMBER },
                longitude: { type: Type.NUMBER }
              },
              required: ['id', 'date', 'title', 'description', 'strategicImpact', 'factionsInvolved', 'location', 'latitude', 'longitude']
            }
          }
        },
        required: ['scenarioName', 'overview', 'events']
      },
      thinkingConfig: { thinkingBudget: 2000 }
    }
  });

  const resultStr = response.text.trim();
  try {
    const data = JSON.parse(resultStr) as GenerationResult;
    // Ensure IDs exist if the model forgot
    data.events = data.events.map((e, idx) => ({
      ...e,
      id: e.id || `event-${idx}`
    }));
    return data;
  } catch (e) {
    console.error("Failed to parse AI response", resultStr);
    throw new Error("Intelligence report corrupted. Try a shorter timeframe or fewer events.");
  }
};

import React from 'react';
import { WarEvent } from '../types';

interface Props {
  events: WarEvent[];
  selectedEventId: string | null;
  onSelectEvent: (id: string) => void;
}

const TacticalMap: React.FC<Props> = ({ events, selectedEventId, onSelectEvent }) => {
  // Simple Mercator projection approximation for SVG
  const mapWidth = 800;
  const mapHeight = 400;

  const project = (lat: number, lng: number) => {
    const x = (lng + 180) * (mapWidth / 360);
    const y = (90 - lat) * (mapHeight / 180);
    return { x, y };
  };

  return (
    <div className="bg-slate-950/80 border border-slate-800 rounded-xl overflow-hidden relative group h-[300px] sm:h-[400px]">
      <div className="absolute top-4 left-4 z-10">
        <span className="text-emerald-500 mono text-[10px] uppercase font-bold tracking-widest bg-slate-950/80 px-2 py-1 rounded border border-emerald-500/30">
          Geographic Deployment Map
        </span>
      </div>

      <svg 
        viewBox={`0 0 ${mapWidth} ${mapHeight}`} 
        className="w-full h-full opacity-60"
        style={{ filter: 'drop-shadow(0 0 10px rgba(16, 185, 129, 0.1))' }}
      >
        {/* Simplified World Outline Background */}
        <rect width={mapWidth} height={mapHeight} fill="#020617" />

        {/* World Grid Lines */}
        <g stroke="#1e293b" strokeWidth="0.5" strokeDasharray="2 2">
          {[...Array(9)].map((_, i) => (
            <line key={`v-${i}`} x1={(i + 1) * (mapWidth / 10)} y1="0" x2={(i + 1) * (mapWidth / 10)} y2={mapHeight} />
          ))}
          {[...Array(4)].map((_, i) => (
            <line key={`h-${i}`} x1="0" y1={(i + 1) * (mapHeight / 5)} x2={mapWidth} y2={(i + 1) * (mapHeight / 5)} />
          ))}
        </g>

        {/* Tactical Markers */}
        {events.map((event) => {
          const { x, y } = project(event.latitude, event.longitude);
          const isSelected = selectedEventId === event.id;

          return (
            <g 
              key={event.id} 
              className="cursor-pointer transition-all duration-300"
              onClick={() => onSelectEvent(event.id)}
            >
              {isSelected && (
                <circle cx={x} cy={y} r="12" fill="none" stroke="#10b981" strokeWidth="1" className="animate-ping" />
              )}
              <circle 
                cx={x} 
                cy={y} 
                r={isSelected ? "6" : "4"} 
                fill={isSelected ? "#10b981" : "#1e293b"} 
                stroke={isSelected ? "#fff" : "#475569"} 
                strokeWidth="1"
                className="hover:fill-emerald-400 transition-colors"
              />
              {isSelected && (
                <text 
                  x={x + 10} 
                  y={y + 4} 
                  fill="#10b981" 
                  fontSize="10" 
                  className="mono font-bold uppercase pointer-events-none drop-shadow-[0_0_2px_black]"
                >
                  {event.location}
                </text>
              )}
            </g>
          );
        })}
      </svg>

      {/* Decorative Scanline */}
      <div className="absolute inset-0 pointer-events-none bg-gradient-to-b from-transparent via-emerald-500/5 to-transparent h-1/2 w-full animate-scan-slow opacity-20"></div>

      <style>{`
        @keyframes scan-slow {
          0% { transform: translateY(-100%); }
          100% { transform: translateY(200%); }
        }
        .animate-scan-slow {
          animation: scan-slow 12s linear infinite;
        }
      `}</style>
    </div>
  );
};

export default TacticalMap;

import React, { useState } from 'react';
import { GenerationResult, WarEvent, SavedScenario } from '../types';
